// ═══ FINDINGS ═══
function initFindings(){
  const findings=[
    {icon:"🏆",text:"<strong>Best Performers:</strong> PMAY Rural (98.7% completion), Atal Schools (93% pass rate), ODOP (₹93K Cr exports), Ayushman Bharat (45L treated)"},
    {icon:"❌",text:"<strong>Underperformers:</strong> Kisan Uday Solar Pumps (15% of target), Kaushal Satrang (poor job outcomes), Sevayojan (low placement rates)"},
    {icon:"⚠️",text:"<strong>Mixed Results:</strong> Kisan Rin Mochan loan waiver was politically popular but many farmers reported non-receipt. Only institutional loans covered."},
    {icon:"📈",text:"<strong>Biggest Reach:</strong> Free Bags & Uniform (1.6 Cr students), Scholarships (80L students), Old Age Pension (56L elderly)"},
    {icon:"💰",text:"<strong>Biggest Budget:</strong> PMAY Rural (₹45,000 Cr), Loan Waiver (₹36,000 Cr), PMAY Urban (₹25,000 Cr)"},
    {icon:"🎯",text:"<strong>Highest Impact:</strong> Atal Schools (9.5/10), PMAY Rural (9.5/10), ODOP (9.0/10), Ayushman Bharat (9.0/10)"},
    {icon:"📊",text:"<strong>Overall:</strong> 67% of schemes performed well (Success+), 21% had mixed results, 8% underperformed, 4% too early to judge"}
  ];
  const grid=document.getElementById('findingsGrid');
  findings.forEach(f=>{grid.innerHTML+=`<div class="finding-card"><div class="fc-icon">${f.icon}</div><div class="fc-text">${f.text}</div></div>`})
}

// ═══ INIT ═══
document.addEventListener('DOMContentLoaded',()=>{
  animateCounters();initSectorCharts();initFilters();initVerdictCharts();initImpact();initFindings();
  // Intersection observer for animations
  const obs=new IntersectionObserver(entries=>{entries.forEach(e=>{if(e.isIntersecting)e.target.style.opacity='1'})},{threshold:0.1});
  document.querySelectorAll('.section').forEach(s=>obs.observe(s))
});
